import{_ as e,c as a,o,a as r}from"./app.e1dfcef5.js";const _=JSON.parse('{"title":"Profesores","description":"","frontmatter":{},"headers":[],"relativePath":"ense\xF1anza/profesores.md"}'),s={name:"ense\xF1anza/profesores.md"},i=r('<h1 id="profesores" tabindex="-1">Profesores <a class="header-anchor" href="#profesores" aria-hidden="true">#</a></h1><p>IesApp permite mantener la informaci\xF3n completa del claustro. Es un sistema de directorio que permite a todo el claustro localizar el correo corporativo de los compa\xF1eros, identificarlo mediante la orla de fotos.</p><p><strong>Plantilla</strong></p><p>Adem\xE1s de ese servicio sencillo de directorio nos permite definir la <strong>plantilla</strong> actual en cada momento. Esta informaci\xF3n s\xF3lo es visibe para jefatura. La plantilla est\xE1 definida para cada curso y cada profesor ocupa una plaza de forma fija, de forma interina (de plantilla sin titular, de cupo sin titular o reserva del titular) o mediante sustituci\xF3n. Esta informaci\xF3n que esb\xE1sica no est\xE1 en ning\xFAn sitio de los sistemas oficiales.</p><p><strong>Horario</strong></p><p>La informaci\xF3n fundamental que tenemos de cada profesor es su horario. Los horarios se importan con el mismo fichero que genera Pe\xF1alara para SIGAD. Es una pieza fundamental para el funcionamiento del centro:</p><ul><li>Est\xE1n siempre actualizados y disponibles para todo el claustro y conserjer\xEDa.</li><li>Son la base del sistema de guardias</li><li>IesApp tambi\xE9n ayuda con la modificaci\xF3n de horarios (FCT/FEOE) de forma coordinada entre jefatura y los profesores interesados.</li></ul>',7),t=[i];function n(l,d,c,p,m,f){return o(),a("div",null,t)}const h=e(s,[["render",n]]);export{_ as __pageData,h as default};
